values
    -- City Center Buildings
    ("LOC_BUILDING_MONUMENT_EXPANSION1_DESCRIPTION",              "Provides +1 Loyalty per turn in this city. After Calendar is researched, provides an additional +1 [ICON_CULTURE] Culture."),
    ("LOC_BUILDING_WALLS_EARLY_NAME",                             "Simple Ancient Wall"),
    ("LOC_BUILDING_WALLS_EARLY_DESCRIPTION",                      "A building unique to your original capital. A Simple Wall that provides 25 outer defense."),
    ("LOC_BUILDING_GRANARY_DESCRIPTION",                          "Camps, Pastures, Lumber Mills and Fishing Boats over bonus resources in this City provide +1 [ICON_Food] Food, doubled after Mathematics is researched."),
    ("LOC_BUILDING_NILOMETER_HD_NAME",                            "Nilometer"),
    ("LOC_BUILDING_NILOMETER_HD_DESCRIPTION",                     "+1 [ICON_Science] Science if the City Center is adjacent to Flood Plains, Oasis or {LOC_MARSH_OR_SWAMP}. After Geomatics is researched, provides an additional +1 [ICON_Science] Science."),
    ("LOC_BUILDING_TSIKHE_DESCRIPTION_XP2",                       "A building unique to Georgia. Lower [ICON_Production] Production cost and higher outer defenses than Medieval Walls it replaces. Provides +5 [ICON_TOURISM] Tourism after advancing to the Conservation Civic. Provides +4 [ICON_Faith] Faith. When in a Golden Age, +300% [ICON_TOURISM] Tourism and +300% [ICON_FAITH] Faith."),
    ("LOC_BUILDING_SEWER_DESCRIPTION",                            "+20% Growth rate in this city."),
    ("LOC_BUILDING_WATER_MILL_NAME",                              "Mill"),
    ("LOC_BUILDING_WATER_MILL_DESCRIPTION",                       "Farms, Plantations, Mines and Quarries over bonus resources in this City provide +1 [ICON_PRODUCTION] Production, doubled after Engineering is researched."),
    ("LOC_BUILDING_FLOOD_BARRIER_NAME",                           "Seawall"),
    ("LOC_BUILDING_PALGUM_DESCRIPTION",                           "A building unique to Babylon. Replaces Mill. Freshwater tiles receive +1 [ICON_FOOD] Food; then receive [ICON_PRODUCTION] Production after Engineering is researched. [NEWLINE][NEWLINE]City must be adjacent to a River. "),
    ("LOC_BUILDING_HD_POLICE_STATION_NAME",                       "Police Station"),
    ("LOC_BUILDING_HD_POLICE_STATION_DESCRIPTION",                "Receive corresponding yield of two copies from each type of districts in this city."),
    -- Campus
    ("LOC_BUILDING_LIBRARY_DESCRIPTION",                          "After Paper Making is researched, [ICON_Citizen] Citizens in this city provide +0.3 [ICON_SCIENCE] Science."),
    ("LOC_BUILDING_UNIVERSITY_DESCRIPTION",                       "[ICON_CITIZEN] Citizens in this city provide +0.5 [ICON_SCIENCE] Science."),
    ("LOC_BUILDING_MADRASA_NAME",                                 "Al-Azhar University"),
    ("LOC_BUILDING_MADRASA_DESCRIPTION",                          "A building unique to Arabia. This building can only be built once per civilization. [NEWLINE][NEWLINE]Campus and Theater Square districts within 6 tiles provide [ICON_Faith] Faith equal to the adjacency bonus. [NEWLINE]For each city follows your Religion, Campus district in this city receives +1 adjacency bonus. If at least 20 cities follow your Religion, your cities can purchase buildings in Campus districts with [ICON_FAITH] Faith. [NEWLINE]For each cultural policy slot in your government, Theater Square district in this city receives +2 adjacency bonus. If your governmrnt has at least 6 cultural policy slots, your cities can purchase buildings in Theater Square districts with [ICON_FAITH] Faith."),
    ("LOC_BUILDING_NAVIGATION_SCHOOL_DESCRIPTION",                "A building unique to Portugal. +25% [ICON_PRODUCTION] Production towards naval units in this city. +1 [ICON_SCIENCE] Science for every 2 Shallow Sea and Lake tiles in this city. +2 [ICON_GreatAdmiral] Great Admiral points. [ICON_CITIZEN] Citizens in this city provide +0.5 [ICON_SCIENCE] Science."),
    ("LOC_BUILDING_RESEARCH_LAB_DESCRIPTION",                     "+5% [ICON_SCIENCE] Science in this city. +10% [ICON_SCIENCE] Science if this city is fully powered. "),
    ("LOC_BUILDING_SEOWON_NAME",                                  "Bibliothecary"),
    ("LOC_BUILDING_HD_DATA_CENTER_NAME",                          "Data Center"),
    ("LOC_BUILDING_HD_DATA_CENTER_DESCRIPTION",                   "+1 Wildcard Policy Slot. After finishing construction, Gain +1600 [ICON_SCIENCE] Science and +1600 [ICON_CULTURE] Culture from each level 3 Alliance. [NEWLINE]Can only be built once in a civilization."),
    -- Theater
    ("LOC_BUILDING_MARAE_DESCRIPTION",                            "A building unique to the Māori. +2 [ICON_CULTURE] Culture and +2 [ICON_FAITH] Faith to all of this city's tiles with a passable feature or natural wonder. +1 [ICON_CULTURE] Culture for every 3 Shallow Sea and Lake tiles in this city. After Flight is researched, receive +1 [ICON_TOURISM] Tourism to all of this city's tiles with a feature or natural wonder. Has no Great Work slots."),
    ("LOC_BUILDING_MUSEUM_ARTIFACT_DESCRIPTION",                  "Holds [ICON_GreatWork_Artifact] Artifacts. May not be built in a Theater Square district that already has an Art Museum. +5% [ICON_CULTURE] Culture in this city."),
    ("LOC_BUILDING_MUSEUM_ART_DESCRIPTION",                       "Holds [ICON_GreatWork_Landscape] Great Works of Art. May not be built in a Theater Square district that already has an Archaeological Museum. +5% [ICON_CULTURE] Culture in this city."),
    ("LOC_BUILDING_FILM_STUDIO_EXPANSION2_DESCRIPTION",           "A building unique to America. +50% [ICON_Tourism] Tourism pressure from this city. +5% [ICON_CULTURE] Culture in this city. +5% [ICON_CULTURE] culture if this city is fully [ICON_POWER] powered."),
    ("LOC_BUILDING_BROADCAST_CENTER_DESCRIPTION",                 "+5% [ICON_CULTURE] Culture in this city. +5% [ICON_CULTURE] Culture if this city is fully [ICON_POWER] powered. "),
    ("LOC_BUILDING_JNR_DOJO_HD_DESCRIPTION",                      "A building unique to the Japan. +25% combat experience for all military units trained in this city. +2 [ICON_Production] Production, +50% [ICON_CULTURE] Culture and [ICON_Tourism] Tourism to Great Works in this city."),
    ("LOC_ABILITY_JNR_DOJO_TRAINED_UNIT_XP_DESCRIPTION",          "+25% Earned experience from Dojo"),
    -- Industrial Zone
    ("LOC_BUILDING_WORKSHOP_DESCRIPTION",                         "Improved tiles in the City have +1 [ICON_Production] Production"), -- , Quarries and Lumber Mills -- Mines in this city gain +1 [ICON_PRODUCTION] Production. +5% [ICON_Production] Production towards wonders, districts and buildings in this city.
    ("LOC_BUILDING_FACTORY_DL_DESCRIPTION",                       "Provide [ICON_Production] Production to cities within 6 tiles."),
    ("LOC_BUILDING_HD_ELECTRONICS_FACTORY_NAME",                  "Electronics Factory"),
    ("LOC_BUILDING_HD_ELECTRONICS_FACTORY_DESCRIPTION",           "+1 [ICON_PRODUCTION] Production for all District in this city, [ICON_CITIZEN] Citizens in this city provide +0.5 [ICON_PRODUCTION] Production. The bonuses are doubled after Integrated Circuit is researched."),
    ("LOC_BUILDING_HD_INTERNET_COMPANY_NAME",                     "Internet Company"),
    ("LOC_BUILDING_HD_INTERNET_COMPANY_DESCRIPTION",              "Campus and Industrial Zone district's adjacency bonus provides [ICON_TOURISM] Tourism as well. +5% [ICON_TOURISM] Tourism across your empire when city is powered."),
    ("LOC_BUILDING_HD_INTERNET_COMPANY_MONOPOLY_DESCRIPTION",     "Campus and Industrial Zone district's adjacency bonus provides [ICON_TOURISM] Tourism as well. +100% [ICON_SCIENCE] Science, [ICON_CULTURE] Culture and [ICON_TOURISM] Tourism to [ICON_Greatwork_Product] Products in this City. +5% [ICON_TOURISM] Tourism across your empire when city is powered."),
    ("LOC_BUILDING_COAL_POWER_PLANT_DL_DESCRIPTION",              "Automatically converts any amount of [ICON_RESOURCE_COAL] Coal into [ICON_Power] Power for cities within 6 tiles that need it each turn, at the rate of:[NEWLINE][ICON_Bullet]1 [ICON_RESOURCE_COAL] Coal [ICON_PowerRight] 4 [ICON_Power] Power[NEWLINE][ICON_Bullet] Heavy CO2 into the atmosphere.[NEWLINE]+10% [ICON_Production] Production towards wonders, districts and buildings in this city."),
    ("LOC_BUILDING_FOSSIL_FUEL_POWER_PLANT_DL_DESCRIPTION",       "Automatically converts any amount of [ICON_RESOURCE_OIL] Oil into [ICON_Power] Power for cities within 6 tiles that need it each turn, at the rate of:[NEWLINE][ICON_Bullet]1 [ICON_RESOURCE_OIL] Oil [ICON_PowerRight] 4 [ICON_Power] Power[NEWLINE][ICON_Bullet] Moderate CO2 into the atmosphere.[NEWLINE]+10% [ICON_Production] Production towards wonders, districts and buildings in this city."),
    ("LOC_BUILDING_POWER_PLANT_DL_DESCRIPTION",                   "Automatically converts any amount of [ICON_RESOURCE_URANIUM] Uranium into [ICON_Power] Power for cities within 6 tiles that need it each turn, at the rate of:[NEWLINE][ICON_Bullet]1 [ICON_RESOURCE_URANIUM] Uranium [ICON_PowerRight] 16 [ICON_Power] Power[NEWLINE][ICON_Bullet]Miniscule CO2 into the atmosphere[NEWLINE]Once built, as a Nuclear Power Plant ages, there is an increased chance for a Nuclear Accident to occur.[NEWLINE]+10% [ICON_Production] Production towards wonders, districts and buildings in this city."),
    -- Holy Site
    ("LOC_BUILDING_SHRINE_DESCRIPTION",                           "Allows the purchasing of Builders using [ICON_Faith] Faith. Allows the purchasing of Missionaries (can only be purchased with [ICON_Faith] Faith)."),
    ("LOC_BUILDING_TEMPLE_DESCRIPTION",                           "Allows the purchasing of Settlers using [ICON_Faith] Faith. Allows the purchasing of Apostles, Gurus, Inquisitors, and with the proper belief, Warrior Monks (these units can only be purchased with [ICON_Faith] Faith)."),
    ("LOC_BUILDING_PRASAT_EXPANSION2_DESCRIPTION",                "A building unique to Khmer. Replaces the Temple. Allows the purchasing of Settlers using [ICON_Faith] Faith. Allows the purchasing of Apostles, Gurus, Inquisitors, and with the proper belief, Warrior Monks (these units can only be purchased with [ICON_Faith] Faith). [ICON_CITIZEN] Citizens in this is provide +0.5 [ICON_Culture] Culture."),
    ("LOC_BUILDING_STAVE_CHURCH_DESCRIPTION",                     "A building unique to Norway. Replaces Temple. Allows the purchasing of Settlers using [ICON_Faith] Faith. Allows the purchasing of Apostles, Gurus, Inquisitors, and with the proper belief, Warrior Monks (these units can only be purchased with [ICON_Faith] Faith). Holy Site districts get an additional standard adjacency bonus from Woods. +1 [ICON_Food] Food to each Forest tile in this city."), --+1 [ICON_TradeRoute] Trade Route capacity. 
    ("LOC_BUILDING_MOSQUE_DL_DESCRIPTION",                        "Missionary and Apostles created here have +1 spread. All Religious units created in this city receive +3 [ICON_Religion] Religious Strength in Theological Combat."),
    ("LOC_BUILDING_PAGODA_DL_NAME",                               "Pagodas"),
    ("LOC_BUILDING_PAGODA_DL_DESCRIPTION",                        "Can hold 2 [ICON_GreatWork_Writing] Great Work of Writing. [NEWLINE] +20% accumulation rate for [ICON_GREATWRITER] Great Writer Points. +4 [ICON_FAITH] Faith, +25% [ICON_CULTURE] Culture and +50% [ICON_Tourism] Tourism for Great Works of Writing in this city."),
    ("LOC_BUILDING_WAT_DL_DESCRIPTION",                           "+10% [ICON_SCIENCE] Science in this city."),
    ("LOC_BUILDING_SYNAGOGUE_DL_DESCRIPTION",                     "+10% [ICON_FAITH] Faith in this city."),
    ("LOC_BUILDING_GURDWARA_DL_DESCRIPTION",                      "+10% [ICON_Food] Food in this city."),
    ("LOC_BUILDING_MEETING_HOUSE_DL_DESCRIPTION",                 "+10% [ICON_PRODUCTION] Production in this city."),
    ("LOC_BUILDING_STUPA_DL_DESCRIPTION",                         "+1 [ICON_AMENITIES] Amenity for every type of Luxury resource this city has improved."),
    ("LOC_BUILDING_CATHEDRAL_DL_DESCRIPTION",                     "Can hold 2 [ICON_GreatWork_Landscape] Great Work of Art and 1 [ICON_GreatWork_Music] Great Work of Music.[NEWLINE] +10% accumulation rate for [ICON_GREATARTIST] Great Artist and [ICON_GREATMUSICIAN] Great Musician Points. +25% [ICON_CULTURE] Culture and +100% [ICON_Tourism] Tourism for Great Works of Art and Music in this city."),
    ("LOC_BUILDING_DAR_E_MEHR_DL_DESCRIPTION",                    "+2 additional [ICON_FAITH] Faith for each era since constructed or last repaired. +10% [ICON_Culture] Culture in this city."),
    ("LOC_BUILDING_HD_ALCHEMY_ROOM_NAME",                         "Alchemy Room"),
    ("LOC_BUILDING_HD_ALCHEMY_ROOM_DESCRIPTION",                  "[ICON_CITIZEN] Citizens in this city provide +0.3 [ICON_SCIENCE] Science. Allows the purchasing of Settlers using [ICON_FAITH] Faith. Allows the purchasing of Apostles, Gurus, Inquisitors, and with the proper belief, Warrior Monks (these units can only be purchased with [ICON_FAITH] Faith)."),
    -- Encampment
    ("LOC_BUILDING_BARRACKS_EXPANSION2_DESCRIPTION",              "+25% combat experience for all melee, anti-cavalry, ranged, and ranged cavalry land units trained in this city.[NEWLINE][NEWLINE]May not be built in an Encampment district that already has a Stable.[NEWLINE][NEWLINE]+2 [ICON_PRODUCTION] Production to each improved [ICON_RESOURCE_IRON] Iron in this city. +2 [ICON_Strength] Combat strength for all melee, ranged, anti-cavalry units trained in this city."),
    ("LOC_BUILDING_BASILIKOI_PAIDES_EXPANSION2_DESCRIPTION",      "A building unique to Macedon. Replaces the Barracks and is unlocked earlier. +25% combat experience for all melee, ranged land units, and Hetairoi trained in this city. Gain [ICON_SCIENCE] Science equal to 25% of the unit's cost when a non civilian unit is created in this city.[NEWLINE][NEWLINE]+2 [ICON_PRODUCTION] Production to each improved [ICON_RESOURCE_IRON] Iron in this city. +3 [ICON_Strength] Combat strength for all land combat, ranged and Hetairoi trained in this city."), -- [NEWLINE][NEWLINE]May not be built in an Encampment district that already has a Stable.
    ("LOC_BUILDING_STABLE_EXPANSION2_DESCRIPTION",                "+25% combat experience for all cavalry and siege class units trained in this city.[NEWLINE][NEWLINE]May not be built in an Encampment district that already has a Barracks.[NEWLINE][NEWLINE]+2 [ICON_PRODUCTION] Production to each improved [ICON_RESOURCE_HORSES] Horses in this city. +2 [ICON_Strength] Combat strength for all cavalry and siege units trained in this city."),
    ("LOC_BUILDING_ORDU_EXPANSION2_DESCRIPTION",                  "A building unique to Mongolia. Replaces Stable. Grants an ability that gives +1 [ICON_MOVEMENT] Movement to Heavy and Light Cavalry trained in this city. +25% combat experience for all cavalry and siege class units trained in this city.[NEWLINE][NEWLINE]May not be built in an Encampment district that already has a Barracks. [NEWLINE][NEWLINE]+2 [ICON_PRODUCTION] Production to each improved [ICON_RESOURCE_HORSES] Horses. +3 [ICON_Strength] Combat strength for all cavalry and siege units, and Keshig trained in this city."),
    ("LOC_BUILDING_ARMORY_EXPANSION2_DESCRIPTION",                "+25% combat experience for all land units trained in this city.[NEWLINE]Strategic Resource Stockpiles increased +30 (on Standard Speed). [NEWLINE][NEWLINE]+1 [ICON_Production] Production to all [ICON_Resource_Niter] Niter and [ICON_Resource_Oil] Oil in this city. Military units trained in this city start with a free promotion (does not overlap)."),
    ("LOC_BUILDING_MILITARY_ACADEMY_EXPANSION2_DESCRIPTION",      "+25% combat experience for all land units trained in this city.[NEWLINE]Allows Corps and Armies to be trained directly. Corps and Army training costs reduced 25%. [NEWLINE][NEWLINE]+1 [ICON_Production] Production to all [ICON_Resource_Aluminum] Aluminum and [ICON_Resource_Uranium] Uranium in this city. +10% accumulation rate for [ICON_GREATGENERAL] Great General Points across the nation. +3 [ICON_STRENGTH] Combat Strength for all land units trained in this city."),
    -- Commercial Hub
    ("LOC_BUILDING_FAIR_NAME",                                    "Fair"),
    ("LOC_BUILDING_MARKET_EXPANSION1_DESCRIPTION",                "+1 [ICON_TradeRoute] Trade Route capacity."),
    ("LOC_BUILDING_SUKIENNICE_NAME",                              "Krakow Sukiennice"),
    ("LOC_BUILDING_SUKIENNICE_EXPANSION1_DESCRIPTION",            "A building unique to Poland. This building can only be built once per civilization. [NEWLINE][NEWLINE]Culture Bomb adjacent tiles when completing a Commercial Hub district. [NEWLINE]For each +8 adjacency bonus of Commercial Hub district in this city, provides +1 [ICON_TradeRoute] Trade Route capacity. Provides [ICON_PRODUCTION] Production equal to 25% adjacency of Commercial Hub district in this city to Domestic [ICON_TRADEROUTE] Trade Routes to this city. Provides [ICON_GOLD] Gold equal to 75% adjacency of Commercial Hub district in this city to International [ICON_TRADEROUTE] Trade Routes starting from this city. [NEWLINE][NEWLINE] When you build International [ICON_TradeRoute] Trade Routes, receive a random luxury resource and its yields in the destination city. This effect can only be obtained once from each destination city."),
    ("LOC_BUILDING_GRAND_BAZAAR_DESCRIPTION",                     "A building unique to the Ottomans. Accumulate 1 extra Strategic resource for every different type of Strategic resource this city has improved. +1 [ICON_AMENITIES] Amenity for every Luxury resource this city has improved. +5% [ICON_gold] Gold yield in this city."),
    ("LOC_BUILDING_BANK_DESCRIPTION",                             "+5% [ICON_gold] Gold in this city."),
    ("LOC_BUILDING_STOCK_EXCHANGE_DESCRIPTION",                   "+10% [ICON_gold] Gold and +10% accumulation rate for [ICON_GREATMERCHANT] Great Merchant Points from all cities within 6 tiles that do not already have a bonus from another Stock Exchange. These bonuses are doubled if the city is fully powered."),
    -- Harbor
    ("LOC_BUILDING_LIGHTHOUSE_EXPANSION2_DESCRIPTION",            "+25% combat experience for all naval units trained in this city. +1 [ICON_Food] Food to all Shallow Sea and Lake tiles in this city. +1 [ICON_TradeRoute] Trade Route capacity."), -- each [ICON_Resource_Fish] Fish, [ICON_Resource_Crabs] Crabs, [ICON_Resource_Whales] Whales, [ICON_Resource_Pearls] Pearls
    ("LOC_BUILDING_SHIPYARD_EXPANSION2_DESCRIPTION",              "+25% combat experience for all naval units trained in this city. Bonus [ICON_Production] Production equal to adjacency bonus of the Harbor district. +1 [ICON_Production] Production on all Shallow Sea and Lake tiles for this city. +25% [ICON_PRODUCTION] production towards all naval units."),
    ("LOC_BUILDING_SEAPORT_DESCRIPTION",                          "+25% combat experience for all naval units trained in this city. Allows Fleets and Armadas to be trained directly. Fleet and Armada training costs reduced by 25%. +1 [ICON_FOOD] Gold on all Shallow Sea and Lake tiles for this city. Bonus [ICON_FOOD] Food equal to adjacency bonus of the Harbor district.[NEWLINE]+10% accumulation rate for [ICON_GREATADMIRAL] Great Admiral Points. +3 [ICON_STRENGTH] Combat Strength for all navy units trained in this city."),
    -- Government
    ("LOC_BUILDING_GOV_WIDE_NAME",                                "Ekklesiasterion"),
    ("LOC_BUILDING_GOV_WIDE_DESCRIPTION",                         "+50% [ICON_PRODUCTION] Production toward Settlers in this City. New cities receive a free Builder. +50% [ICON_Production] Production towards buildings in City Center which are already built in this city."),
    ("LOC_BUILDING_GOV_TALL_DESCRIPTION",                         "+2 [ICON_Housing] Housing in all cities.[NEWLINE]+20% construction speed towards wonders, districts and buildings in this city, and can build 1 more district than the [ICON_CITIZEN] Population limit allows.[NEWLINE]Awards +1 [ICON_Governor] Governor Title."),
    ("LOC_BUILDING_GOV_CONQUEST_DESCRIPTION",                     "Capturing an enemy City grants 15% bonus [ICON_Production] Production in all Cities for 5 turns.[NEWLINE]+20% [ICON_Production] Production towards training military units in this city. [NEWLINE]+100% Yields gained from pilaging and coastal raids.[NEWLINE]Awards +1 [ICON_Governor] Governor Title."),
    ("LOC_BUILDING_GOV_SPIES_NAME",                               "Secretariat"),
    ("LOC_BUILDING_GOV_SPIES_HD_DESCRIPTION",                     "Your cities +10% [ICON_Food] Food and +10% [ICON_Production] Production. Double these bonus for Cities with a [ICON_Governor] Governor established.[NEWLINE]Awards +1 [ICON_Governor] Governor Title."),
    ("LOC_BUILDING_GOV_FAITH_NAME",                               "Episcopal Church"),
    ("LOC_BUILDING_GOV_FAITH_HD_DESCRIPTION",                     "+10% [ICON_Faith] Faith to cities with Holy Site district. Receive [ICON_Science] Science and [ICON_Culture] Culture equal to 10% of your [ICON_Faith] Faith output in all cities.[NEWLINE]Religious units are 20% cheaper to purchase in all cities. +5 [ICON_Religion] Religious Strength in Theological Combat.[NEWLINE]Awards +1 [ICON_Governor] Governor Title."),
    ("LOC_BUILDING_GOV_CITYSTATES_NAME",                          "Trade Capital"),
    ("LOC_BUILDING_GOV_CITYSTATES_HD_DESCRIPTION",                "+1 [ICON_TRADEROUTE] Trade Route capacity. Grants a free Traders. -10% cost when purchasing a Trader. Starting a [ICON_TRADEROUTE] Trade Route immediately creates a [ICON_TRADINGPOST] Trading Post in the destination city. Your [ICON_TRADEROUTE] Trade Routes provide additional +1 [ICON_GOLD] Gold for passing through each of your [ICON_TRADINGPOST] Trading Post in foreign city. City with a [ICON_GOVERNOR] Governor +15% [ICON_GOLD] Gold. [NEWLINE]Awards +1 [ICON_GOVERNOR] Governor Title."),
    ("LOC_BUILDING_GOV_CITYSTATES_MONOPOLY_DESCRIPTION",          "+1 [ICON_TRADEROUTE] Trade Route capacity. Grants a free Traders. -10% cost when purchasing a Trader. Starting a [ICON_TRADEROUTE] Trade Route immediately creates a [ICON_TRADINGPOST] Trading Post in the destination city. Your [ICON_TRADEROUTE] Trade Routes provide additional +1 [ICON_GOLD] Gold for passing through each of your [ICON_TRADINGPOST] Trading Post in foreign city. City with a [ICON_GOVERNOR] Governor +15% [ICON_GOLD] Gold. Grants a Tycoon and a Investor after researching their required Technologies. [NEWLINE]Awards +1 [ICON_GOVERNOR] Governor Title."),
    ("LOC_BUILDING_GOV_SCIENCE_DESCRIPTION",                      "Campus Buildings provide [ICON_Production] Production equal to their basic [ICON_Science] Science yield.[NEWLINE]Industrial Zone Buildings provide [ICON_Science] Science equal to their basic [ICON_Production] Production yield.[NEWLINE]Awards +1 [ICON_Governor] Governor Title."),
    --("LOC_BUILDING_GOV_SCIENCE_DESCRIPTION",                      "Builders gain the ability to use all of their charges to provide bonus [ICON_Production] Production to a District Project (2% per charge). Once per city per turn.[NEWLINE]Awards +1 [Icon_Governor] Governor Title."),
    ("LOC_BUILDING_GOV_MILITARY_DESCRIPTION",                     "All military units gain +1 [ICON_Movement] Movement and +3 [ICON_Strength] Combat Strength.[NEWLINE]Unit maintenance cost reduced by 2 [ICON_Gold] Gold per turn, per unit.[NEWLINE]25% [ICON_Gold] Gold and Resource discount on all unit upgrades.[NEWLINE]Awards +1 [ICON_Governor] Governor Title."),
    ("LOC_BUILDING_GOV_CULTURE_DESCRIPTION",                      "Provides 6 slots for any Great Work. +100% and [ICON_Tourism] Tourism to all Great Works, extra +100% in this city. +20% [ICON_TOURISM] Tourism across your empire. +25% [ICON_CULTURE] Culture to cities with an Art Museum or an Artifact Museum. [NEWLINE]Awards +1 [Icon_Governor] Governor Title."),
    ("LOC_ABILITY_GOV_FAITH_COMBAT_STRENGTH_DESCRIPTION",         "+5 [ICON_Religion] Religious Combat Strength from Episcopal Church."),
    ("LOC_ABILITY_GOV_MILITARY_MOVEMENT_DESCRIPTION",             "+1 [ICON_Movement] Movement from War Department."),
    ("LOC_ABILITY_GOV_MILITARY_COMBAT_STRENGTH_DESCRIPTION",      "+3 [ICON_Strength] Combat Strength from War Department."),
    ("LOC_BUILDING_QUEENS_BIBLIOTHEQUE_DESCRIPTION",              "A building unique to Sweden. Provides 6 slots for any Great Work. +100% [ICON_Tourism] Tourism to Great Works in this city, extra +100% [ICON_Tourism] Tourism to [ICON_GreatWork_Writing] Great Work of Writing. Provides extra 3% [ICON_CULTURE] Culture for Inspiration. Grant boost [ICON_CIVICBOOSTED] to 'Opera and Ballet' (complete 'Opera and Ballet' if already boosted). [NEWLINE]Awards +1 [ICON_GOVERNOR] Governor Title."),
    ("LOC_BUILDING_EL_ESCORIAL_PALACE_NAME",                      "El Escorial Palace"),
    ("LOC_BUILDING_EL_ESCORIAL_PALACE_DESCRIPTION",               "A building unique to Philip II. Each time you ""Explore City of Gold"", provide the basic yields or adjacency yields of this natural wonder to your Palace and this building, and provide +2 [ICON_GreatProphet] Great Prophet points, +2 [ICON_GreatWriter] Great Writer points and +2 [ICON_GreatArtist] Great Artist points per turn to this building. +50% [ICON_CULTURE] Culture and [ICON_Faith] Faith to [ICON_GreatWork_Relic] Great Work of Relic, [ICON_GreatWork_Writing] Great Work of Writing and [ICON_GreatWork_Landscape] Great Work of Art."),
    -- Diplomatic Quarter
    ("LOC_BUILDING_CONSULATE_DESCRIPTION",                        "+2 Influence Points per turn. Gain +1 [ICON_ENVOY] Envoy. Leveraging City States costs 20% less [ICON_Gold] Gold. +50% construction speed towards Spy in this city. Your Spy units can choose from any possible promotion."),
    ("LOC_BUILDING_CHANCERY_DESCRIPTION",                         "+3 Influence Points per turn. Gain +1 [ICON_ENVOY] Envoy. +1 [ICON_VISLIMITED] Visibility level on all other Civs. +50% [ICON_PRODUCTION] toward Spies in all Cities. Receive one Spy and +1 Spy capacity. Spys start with a free promotion. All Spy Operations have a higher chance of success. Spy mission time reduces by 15%. When this civilization captures or kills an enemy Spy, receive 50 [ICON_SCIENCE] Science for every level of the enemy Spy."),
    ("LOC_BUILDING_HD_REGIONAL_COUNCIL_CENTER_NAME",              "Regional Council Centre"),
    ("LOC_BUILDING_HD_REGIONAL_COUNCIL_CENTER_DESCRIPTION",       "+1 Cultural Policy Slot. +1 Dipolomatic Victory Point. +25% Influence points. +1 Diplomatic visibility towards all civilizations. Accumulates 5 extra Alliance Points per turn. Double bonus of [ICON_TRADEROUTE] Trade Routes from alliances. Enemy Spy level reduced by 1 in your lands. [NEWLINE]Awards +1 [ICON_Governor] Governor Title. [NEWLINE]Can only be built once in a civilization."),
    ("LOC_BUILDING_HD_WORLD_PARLIAMENT_HEADQUARTERS_NAME",        "World Parliament Headquarters"),
    ("LOC_BUILDING_HD_WORLD_PARLIAMENT_HEADQUARTERS_DESCRIPTION", "Building unique to America. +1 Cultural Policy Slot. +3 Dipolomatic Victory Point. +50% Influence points. +1 Diplomatic visibility towards all civilizations. Accumulates 5 extra Alliance Points per turn. Double bonus of [ICON_TRADEROUTE] Trade Routes from alliances. If you are the suzerain of at least 1 City States of the same type, all of your cities receive +10% of the respective yield. Your Spy level is increased by 1 for all offensive operations，enemy Spy level reduced by 1 in your lands. [NEWLINE]Awards +1 [ICON_Governor] Governor Title. [NEWLINE]Can only be built once in a civilization."),
    ("LOC_TRAIT_CIVILIZATION_BUILDING_HD_WORLD_PARLIAMENT_HEADQUARTERS_NAME",               "American unique building: World Parliament Headquarters"),
    ("LOC_BUILDING_HD_HUMAN_RIGHTS_COUNCIL_NAME",                 "Human Rights Council"),
