    ("LOC_BUILDING_HD_LANDFORM_EPO_NAME",                         "Landscape Ecology Protection Agency"),
    ("LOC_BUILDING_HD_LANDFORM_EPO_DESCRIPTION",                  "+8 [ICON_SCIENCE] Science [ICON_CULTURE] Culture for every type of Feature within your empire (not including Natural Wonders). [NEWLINE][NEWLINE]Can only be built once in a civilization."),
