    ("zh_Hans_CN",  "LOC_BUILDING_SEWER_DESCRIPTION",                            "本城+20%余粮。"),
    ("zh_Hans_CN",  "LOC_BUILDING_TSIKHE_DESCRIPTION_XP2",                       "格鲁吉亚特色建筑。[ICON_Production] 生产力花费低于中世纪城墙，并拥有更强的外部防御力。获得“保护地球”市政后提供+5点 [ICON_TOURISM] 旅游业绩。提供+4 [ICON_Faith] 信仰值。进入黄金时代后 [ICON_TOURISM] 旅游业绩与 [ICON_FAITH] 信仰值均+300%。"),
    ("zh_Hans_CN",  "LOC_BUILDING_WATER_MILL_NAME",                              "磨坊"),
